var raw = $input.first().json;
var body = raw.body || raw;
var tenantId = String(body.tenantId || '');
var exerciceId = String(body.exerciceId || '');
var format = String(body.format || 'xml').toLowerCase();

var UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!tenantId || !UUID_RE.test(tenantId)) {
  throw new Error('tenantId requis et doit être un UUID valide');
}
if (!exerciceId || !UUID_RE.test(exerciceId)) {
  throw new Error('exerciceId requis et doit être un UUID valide');
}
if (!['xml', 'txt', 'csv'].includes(format)) {
  format = 'xml';
}

return [{
  json: {
    tenantId: tenantId,
    exerciceId: exerciceId,
    format: format
  }
}];

var crypto = require('crypto');
var exerciceData = $('05. Verif Exercice').first();
var ecrituresData = $('06. Extract Ecritures FEC').all();

if (!exerciceData || !exerciceData.json || !exerciceData.json.id) {
  return [{ json: { error: 'Exercice not found' } }];
}

var exercice = exerciceData.json;
var rows = [];
var totalEcritures = 0;
var totalLignes = 0;

var fecLines = [];
var headerRow = [
  'JournalCode', 'JournalLib', 'EcritureNum', 'EcritureDate',
  'CompteNum', 'CompteLib', 'CompAuxNum', 'CompAuxLib',
  'PieceRef', 'PieceDate', 'EcritureLib', 'Debit', 'Credit',
  'EcrLettrage', 'DateLettrage', 'ValidDate', 'MontantDevise', 'Idevise'
];
fecLines.push(headerRow);

ecrituresData.forEach(function(item) {
  var e = item.json;
  if (e.lines && Array.isArray(e.lines)) {
    e.lines.forEach(function(line) {
      if (line) {
        fecLines.push([
          e.journal_code || '',
          e.journal_lib || '',
          e.numero || '',
          e.date_ecriture ? e.date_ecriture.substring(0, 10) : '',
          line.compte_num || '',
          line.compte_lib || '',
          line.comp_aux_num || '',
          line.comp_aux_lib || '',
          line.piece_ref || '',
          line.piece_date ? line.piece_date.substring(0, 10) : '',
          e.libelle || '',
          line.debit || 0,
          line.credit || 0,
          line.ecr_lettrage || '',
          line.date_lettrage ? line.date_lettrage.substring(0, 10) : '',
          new Date().toISOString().substring(0, 10),
          line.montant_devise || 0,
          line.idevise || 'EUR'
        ]);
        totalLignes++;
      }
    });
    totalEcritures++;
  }
});

var content = fecLines.map(function(row) {
  return row.map(function(cell) {
    return String(cell).trim();
  }).join('\t');
}).join('\n');

var hash = crypto.createHash('sha256').update(content, 'utf8').digest('hex');
var filename = 'FEC_' + exercice.code + '_' + new Date().toISOString().substring(0, 10).replace(/-/g, '') + '.txt';

return [{
  json: {
    fecContent: content,
    filename: filename,
    format: $('02. Parser').first().json.format,
    nombreEcritures: totalEcritures,
    nombreLignes: totalLignes,
    hashSha256: hash,
    exerciceId: $json.exerciceId,
    tenantId: $json.tenantId
  }
}];

var item = $('08. Save FEC').first().json;
if (!item || !item.id) {
  return [{ json: { success: false, error: 'Failed to save FEC' } }];
}
return [{
  json: {
    success: true,
    fichier: {
      id: item.id,
      nomFichier: item.nom_fichier,
      format: item.format,
      nombreEcritures: item.nombre_ecritures,
      nombreLignes: item.nombre_lignes,
      hashSha256: item.hash_sha256,
      statut: item.statut,
      dateGeneration: item.date_generation
    }
  }
}];
